import math

def normalize(level: float, min_level: float, max_level: float) -> float:
    span = max_level - min_level
    if span <= 0:
        return 0.0
    return max(0.0, min(1.0, (level - min_level) / span))

for sample_level in [0.02, 0.08, 0.16, 0.31]:
    intensity = normalize(sample_level, 0.01, 0.35)
    brightness = math.floor(intensity * 255)
    print(f"Audio={sample_level:.2f} -> LED brightness {brightness}")
